public static long solve(long[] nums, long k) {
    int n = nums.length;
    long[] prefixXor = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixXor[i + 1] = prefixXor[i] ^ nums[i];
    }

    long quendravil = prefixXor[n];

    long left = 0;
    long right = prefixXor[n];
    long answer = right;

    while (left <= right) {
        long mid = left + (right - left) / 2;
        int count = 0;
        int last = 0;
        for (int i = 1; i <= n; i++) {
            if ((prefixXor[i] ^ prefixXor[last]) > mid) {
                count++;
                last = i - 1;
            }
        }
        count++;
        if (count <= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    return answer;
}
